def findPeakGrid(m,n, mat):
    left, right = 0, n - 1

    while left <= right:
        mid_col = (left + right) // 2

        # Find row index of maximum element in mid_col
        max_row = 0
        for i in range(1, m):
            if mat[i][mid_col] > mat[max_row][mid_col]:
                max_row = i

        left_val = mat[max_row][mid_col - 1] if mid_col > 0 else -1
        right_val = mat[max_row][mid_col + 1] if mid_col < n - 1 else -1

        # Check if current element is a peak
        if mat[max_row][mid_col] > left_val and mat[max_row][mid_col] > right_val:
            return [max_row, mid_col]

        # Move search direction
        if right_val > mat[max_row][mid_col]:
            left = mid_col + 1
        else:
            right = mid_col - 1

    return [-1, -1]  # Should never happen

