/**
 * Note: The returned array must be allocated dynamically.
 * It contains exactly 2 elements: [row_index, col_index].
 */
 #include <stdbool.h>
int* findPeakGrid(int m, int n, int mat[m][n]) {
    int startCol = 0, endCol = n - 1;

    // Allocate dynamic memory for returning 2 values [row, col]
    int* res = (int*)malloc(2 * sizeof(int));

    // Binary Search on Columns
    while (startCol <= endCol) {
        int midCol = startCol + (endCol - startCol) / 2;

        // Find the row index of the maximum element in the midCol column
        int maxRow = 0;
        for (int r = 1; r < m; r++) {
            if (mat[r][midCol] > mat[maxRow][midCol]) {
                maxRow = r;
            }
        }

        // Check left and right neighbors
        bool leftIsLarger = (midCol - 1 >= 0) && (mat[maxRow][midCol - 1] > mat[maxRow][midCol]);
        bool rightIsLarger = (midCol + 1 < n) && (mat[maxRow][midCol + 1] > mat[maxRow][midCol]);

        if (!leftIsLarger && !rightIsLarger) {
            // Found a peak element! Store in array and return
            res[0] = maxRow;
            res[1] = midCol;
            return res;
        } else if (leftIsLarger) {
            // Peak must exist on the left side
            endCol = midCol - 1;
        } else {
            // Peak must exist on the right side
            startCol = midCol + 1;
        }
    }

    // Safeguard fallback
    res[0] = -1;
    res[1] = -1;
    return res;
}

