public static int[] findPeakGrid(int m,int n, int[][] mat) {

    int left = 0, right = n - 1;

    while (left <= right) {
        int midCol = left + (right - left) / 2;

        // Find row index of the maximum element in midCol
        int maxRow = 0;
        for (int i = 1; i < m; i++) {
            if (mat[i][midCol] > mat[maxRow][midCol]) {
                maxRow = i;
            }
        }

        int leftVal  = (midCol > 0)     ? mat[maxRow][midCol - 1] : -1;
        int rightVal = (midCol < n - 1) ? mat[maxRow][midCol + 1] : -1;

        // Check if it's a peak
        if (mat[maxRow][midCol] > leftVal &&
            mat[maxRow][midCol] > rightVal) {
            return new int[]{maxRow, midCol};
        }

        // Move the search space
        if (rightVal > mat[maxRow][midCol]) {
            left = midCol + 1;
        } else {
            right = midCol - 1;
        }
    }

    return new int[]{-1, -1}; // Should never be reached
}

